2010 /// be a power of two when defined. Supports values with integer or pointer
2011 /// types and vectors of integers.
2012 bool isKnownToBeAPowerOfTwo(const Value *V, bool OrZero, unsigned Depth,
2013                             const SimplifyQuery &Q) {
2014   assert(Depth <= MaxAnalysisRecursionDepth && "Limit Search Depth");
2015 
2016   if (isa<Constant>(V))
2017     return OrZero ? match(V, m_Power2OrZero()) : match(V, m_Power2());
2018 
2019   auto *I = dyn_cast<Instruction>(V);
2020   if (!I)
2021     return false;
2022 
2023   if (Q.CxtI && match(V, m_VScale())) {
2024     const Function *F = Q.CxtI->getFunction();
2025     // The vscale_range indicates vscale is a power-of-two.
2026     return F->hasFnAttribute(Attribute::VScaleRange);
2027   }
2028 
2029   // 1 << X is clearly a power of two if the one is not shifted off the end.  If
2030   // it is shifted off the end then the result is undefined.
2031   if (match(I, m_Shl(m_One(), m_Value())))
2032     return true;
2033 
2034   // (signmask) >>l X is clearly a power of two if the one is not shifted off
2035   // the bottom.  If it is shifted off the bottom then the result is undefined.
2036   if (match(I, m_LShr(m_SignMask(), m_Value())))
2037     return true;
2038 
2039   // The remaining tests are all recursive, so bail out if we hit the limit.
2040   if (Depth++ == MaxAnalysisRecursionDepth)
2041     return false;
2042 
2043   switch (I->getOpcode()) {
2044   case Instruction::ZExt:
2045     return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2046   case Instruction::Shl:
2047     if (OrZero || Q.IIQ.hasNoUnsignedWrap(I) || Q.IIQ.hasNoSignedWrap(I))
2048       return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2049     return false;
2050   case Instruction::LShr:
2051     if (OrZero || Q.IIQ.isExact(cast<BinaryOperator>(I)))
2052       return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2053     return false;
2054   case Instruction::UDiv:
2055     if (Q.IIQ.isExact(cast<BinaryOperator>(I)))
2056       return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2057     return false;
2058   case Instruction::And:
2059     if (OrZero) {
2060       // A power of two and'd with anything is a power of two or zero.
2061       if (isKnownToBeAPowerOfTwo(I->getOperand(0), /*OrZero*/ true, Depth, Q) ||
2062           isKnownToBeAPowerOfTwo(I->getOperand(1), /*OrZero*/ true, Depth, Q))
2063         return true;
2064       // X & (-X) is always a power of two or zero.
2065       if (match(I->getOperand(0), m_Neg(m_Specific(I->getOperand(1)))) ||
2066           match(I->getOperand(1), m_Neg(m_Specific(I->getOperand(0)))))
2067         return true;
2068     }
2069     return false;
2070   case Instruction::Add: {
2071     // Adding a power-of-two or zero to the same power-of-two or zero yields
2072     // either the original power-of-two, a larger power-of-two or zero.
2073     const OverflowingBinaryOperator *VOBO = cast<OverflowingBinaryOperator>(V);
2074     if (OrZero || Q.IIQ.hasNoUnsignedWrap(VOBO) ||
2075         Q.IIQ.hasNoSignedWrap(VOBO)) {
2076       if (match(I->getOperand(0),
2077                 m_c_And(m_Specific(I->getOperand(1)), m_Value())) &&
2078           isKnownToBeAPowerOfTwo(I->getOperand(1), OrZero, Depth, Q))
2079         return true;
2080       if (match(I->getOperand(1),
2081                 m_c_And(m_Specific(I->getOperand(0)), m_Value())) &&
2082           isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q))
2083         return true;
2084 
2085       unsigned BitWidth = V->getType()->getScalarSizeInBits();
2086       KnownBits LHSBits(BitWidth);
2087       computeKnownBits(I->getOperand(0), LHSBits, Depth, Q);
2088 
2089       KnownBits RHSBits(BitWidth);
2090       computeKnownBits(I->getOperand(1), RHSBits, Depth, Q);
2091       // If i8 V is a power of two or zero:
2092       //  ZeroBits: 1 1 1 0 1 1 1 1
2093       // ~ZeroBits: 0 0 0 1 0 0 0 0
2094       if ((~(LHSBits.Zero & RHSBits.Zero)).isPowerOf2())
2095         // If OrZero isn't set, we cannot give back a zero result.
2096         // Make sure either the LHS or RHS has a bit set.
2097         if (OrZero || RHSBits.One.getBoolValue() || LHSBits.One.getBoolValue())
2098           return true;
2099     }
2100     return false;
2101   }
2102   case Instruction::Select:
2103     return isKnownToBeAPowerOfTwo(I->getOperand(1), OrZero, Depth, Q) &&
2104            isKnownToBeAPowerOfTwo(I->getOperand(2), OrZero, Depth, Q);
2105   case Instruction::PHI: {
2106     // A PHI node is power of two if all incoming values are power of two, or if
2107     // it is an induction variable where in each step its value is a power of
2108     // two.
2109     auto *PN = cast<PHINode>(I);
2110     SimplifyQuery RecQ = Q;
2111 
2112     // Check if it is an induction variable and always power of two.
2113     if (isPowerOfTwoRecurrence(PN, OrZero, Depth, RecQ))
2114       return true;
2115 
2116     // Recursively check all incoming values. Limit recursion to 2 levels, so
2117     // that search complexity is limited to number of operands^2.
2118     unsigned NewDepth = std::max(Depth, MaxAnalysisRecursionDepth - 1);
2119     return llvm::all_of(PN->operands(), [&](const Use &U) {
2120       // Value is power of 2 if it is coming from PHI node itself by induction.
2121       if (U.get() == PN)
2122         return true;
2123 
2124       // Change the context instruction to the incoming block where it is
2125       // evaluated.
2126       RecQ.CxtI = PN->getIncomingBlock(U)->getTerminator();
2127       return isKnownToBeAPowerOfTwo(U.get(), OrZero, NewDepth, RecQ);
2128     });
2129   }
2130   case Instruction::Call: {
2131     Value *X, *Y;
2132     if (match(I, m_MaxOrMin(m_Value(X), m_Value(Y))))
2133       return isKnownToBeAPowerOfTwo(X, OrZero, Depth, Q) &&
2134              isKnownToBeAPowerOfTwo(Y, OrZero, Depth, Q);
2135     return false;
2136   }
2137   default:
2138     return false;
2139   }
2140 }
