2697 // Canonicalize select with fcmp to fabs(). -0.0 makes this tricky. We need
2698 // fast-math-flags (nsz) or fsub with +0.0 (not fneg) for this to work.
2699 static Instruction *foldSelectWithFCmpToFabs(SelectInst &SI,
2700                                              InstCombinerImpl &IC) {
2701   Value *CondVal = SI.getCondition();
2702 
2703   bool ChangedFMF = false;
2704   for (bool Swap : {false, true}) {
2705     Value *TrueVal = SI.getTrueValue();
2706     Value *X = SI.getFalseValue();
2707     CmpInst::Predicate Pred;
2708 
2709     if (Swap)
2710       std::swap(TrueVal, X);
2711 
2712     if (!match(CondVal, m_FCmp(Pred, m_Specific(X), m_AnyZeroFP())))
2713       continue;
2714 
2715     // fold (X <= +/-0.0) ? (0.0 - X) : X to fabs(X), when 'Swap' is false
2716     // fold (X >  +/-0.0) ? X : (0.0 - X) to fabs(X), when 'Swap' is true
2717     if (match(TrueVal, m_FSub(m_PosZeroFP(), m_Specific(X)))) {
2718       if (!Swap && (Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE)) {
2719         Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
2720         return IC.replaceInstUsesWith(SI, Fabs);
2721       }
2722       if (Swap && (Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT)) {
2723         Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
2724         return IC.replaceInstUsesWith(SI, Fabs);
2725       }
2726     }
2727 
2728     if (!match(TrueVal, m_FNeg(m_Specific(X))))
2729       return nullptr;
2730 
2731     // Forward-propagate nnan and ninf from the fneg to the select.
2732     // If all inputs are not those values, then the select is not either.
2733     // Note: nsz is defined differently, so it may not be correct to propagate.
2734     FastMathFlags FMF = cast<FPMathOperator>(TrueVal)->getFastMathFlags();
2735     if (FMF.noNaNs() && !SI.hasNoNaNs()) {
2736       SI.setHasNoNaNs(true);
2737       ChangedFMF = true;
2738     }
2739     if (FMF.noInfs() && !SI.hasNoInfs()) {
2740       SI.setHasNoInfs(true);
2741       ChangedFMF = true;
2742     }
2743 
2744     // With nsz, when 'Swap' is false:
2745     // fold (X < +/-0.0) ? -X : X or (X <= +/-0.0) ? -X : X to fabs(X)
2746     // fold (X > +/-0.0) ? -X : X or (X >= +/-0.0) ? -X : X to -fabs(x)
2747     // when 'Swap' is true:
2748     // fold (X > +/-0.0) ? X : -X or (X >= +/-0.0) ? X : -X to fabs(X)
2749     // fold (X < +/-0.0) ? X : -X or (X <= +/-0.0) ? X : -X to -fabs(X)
2750     //
2751     // Note: We require "nnan" for this fold because fcmp ignores the signbit
2752     //       of NAN, but IEEE-754 specifies the signbit of NAN values with
2753     //       fneg/fabs operations.
2754     if (!SI.hasNoSignedZeros() || !SI.hasNoNaNs())
2755       return nullptr;
2756 
2757     if (Swap)
2758       Pred = FCmpInst::getSwappedPredicate(Pred);
2759 
2760     bool IsLTOrLE = Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_OLE ||
2761                     Pred == FCmpInst::FCMP_ULT || Pred == FCmpInst::FCMP_ULE;
2762     bool IsGTOrGE = Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_OGE ||
2763                     Pred == FCmpInst::FCMP_UGT || Pred == FCmpInst::FCMP_UGE;
2764 
2765     if (IsLTOrLE) {
2766       Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
2767       return IC.replaceInstUsesWith(SI, Fabs);
2768     }
2769     if (IsGTOrGE) {
2770       Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
2771       Instruction *NewFNeg = UnaryOperator::CreateFNeg(Fabs);
2772       NewFNeg->setFastMathFlags(SI.getFastMathFlags());
2773       return NewFNeg;
2774     }
2775   }
2776 
2777   return ChangedFMF ? &SI : nullptr;
